eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   AFTERMATH: () => (/* binding */ AFTERMATH),\n/* harmony export */   ECOSYSTEM: () => (/* binding */ ECOSYSTEM),\n/* harmony export */   FAQ: () => (/* binding */ FAQ),\n/* harmony export */   FINAL_CTA: () => (/* binding */ FINAL_CTA),\n/* harmony export */   FOOTER: () => (/* binding */ FOOTER),\n/* harmony export */   HERO: () => (/* binding */ HERO),\n/* harmony export */   MENTOR: () => (/* binding */ MENTOR),\n/* harmony export */   META: () => (/* binding */ META),\n/* harmony export */   NAV_LINKS: () => (/* binding */ NAV_LINKS),\n/* harmony export */   POWERED_BY: () => (/* binding */ POWERED_BY),\n/* harmony export */   PROBLEM: () => (/* binding */ PROBLEM),\n/* harmony export */   PROGRAM: () => (/* binding */ PROGRAM),\n/* harmony export */   QUALIFICATION: () => (/* binding */ QUALIFICATION),\n/* harmony export */   STATS_HERO: () => (/* binding */ STATS_HERO),\n/* harmony export */   TESTIMONIALS: () => (/* binding */ TESTIMONIALS),\n/* harmony export */   TIMELINE: () => (/* binding */ TIMELINE)\n/* harmony export */ });\n// All textual content for AI CEO Circle by MAXY AI landing page.\n// Keep this file as the single source of truth for copy.\nconst META = {\n    brand: \"AI CEO Circle\",\n    byline: \"by MAXY AI\",\n    contactEmail: \"hello@aiceocircle.com\",\n    social: \"@aiceocircle\",\n    cohort: \"Cohort 01 · September 2026\",\n    topbar: \"Indonesia · Singapore · Global standard\"\n};\nconst NAV_LINKS = [\n    {\n        label: \"Ecosystem\",\n        href: \"#ecosystem\"\n    },\n    {\n        label: \"Program\",\n        href: \"#program\"\n    },\n    {\n        label: \"Format\",\n        href: \"#format\"\n    },\n    {\n        label: \"Mentor\",\n        href: \"#mentor\"\n    },\n    {\n        label: \"FAQ\",\n        href: \"#faq\"\n    }\n];\nconst HERO = {\n    eyebrow: \"AI CEO Circle · Powered by MAXY AI\",\n    titleA: \"Lead the AI era.\",\n    titleB: \"Don't just survive it.\",\n    description: \"AI CEO Circle is MAXY AI's exclusive 6-month executive mentoring program — where CEOs and senior business leaders in Indonesia and Singapore build their own AI agents and a Digital CEO Twin alongside practitioners who have already done it.\",\n    ctaPrimary: \"Apply for the next cohort\",\n    ctaSecondary: \"Download program overview\"\n};\nconst POWERED_BY = [\n    \"Powered by MAXY AI\",\n    \"Next cohort · Sep 2026\",\n    \"Max 15 CEOs\",\n    \"Application required\",\n    \"Indonesia · Singapore\",\n    \"Bilingual · EN / ID\",\n    \"Practitioners, not lecturers\"\n];\nconst STATS_HERO = [\n    {\n        value: \"15\",\n        label: \"Seats per cohort\"\n    },\n    {\n        value: \"6\",\n        label: \"Months program\"\n    },\n    {\n        value: \"1\",\n        label: \"AI agent built\"\n    },\n    {\n        value: \"1\",\n        label: \"Digital CEO Twin\"\n    },\n    {\n        value: \"3\",\n        label: \"Live events\"\n    }\n];\nconst ECOSYSTEM = {\n    label: \"About MAXY AI\",\n    title: \"AI CEO Circle is backed by a full AI transformation ecosystem\",\n    intro: \"MAXY AI isn't a training company that decided to run a CEO program. We are a full-stack AI company — and AI CEO Circle is the executive entry point into everything we build.\",\n    cards: [\n        {\n            tag: \"B2C · Gen Z\",\n            title: \"MAXY Academy\",\n            body: \"AI and digital-skills bootcamps and certifications for university students and fresh graduates. Upskill young talent — then place them inside enterprises.\"\n        },\n        {\n            tag: \"B2B · Enterprise · Gov\",\n            title: \"MAXY AI Digital Training\",\n            body: \"Function-specific AI training for enterprises and government: CEO, HR, marketing, sales, content, operations, finance — plus full AI transformation roadmaps.\"\n        },\n        {\n            tag: \"Implementation · Builds\",\n            title: \"Agentic AI Solutions\",\n            body: \"After training, MAXY AI builds and deploys agentic AI systems inside enterprise operations. Real automation. Real outcomes. Not slides.\"\n        }\n    ],\n    outro: \"AI CEO Circle is the executive entry point. Once you join, your entire organization unlocks access to MAXY AI's training, agentic AI builds, and AI-native talent placement — a full transformation journey, not a one-time program.\",\n    pillars: [\n        {\n            tag: \"B2C + B2B\",\n            text: \"Dual-track AI education ecosystem\"\n        },\n        {\n            tag: \"ID + SG\",\n            text: \"Indonesia primary · Singapore active\"\n        },\n        {\n            tag: \"3 tracks\",\n            text: \"Students · Enterprises · C-Suite\"\n        },\n        {\n            tag: \"End-to-end\",\n            text: \"Train → Transform → Place talent\"\n        }\n    ]\n};\nconst PROBLEM = {\n    label: \"The problem\",\n    title: \"The real AI problem isn't technology. It's leadership.\",\n    intro: \"Most CEOs have attended AI workshops. Most have told their team to 'explore AI.' Nothing in their business has fundamentally changed.\",\n    items: [\n        {\n            n: \"01\",\n            title: \"You have the knowledge. Not the build.\",\n            body: \"Every program teaches what AI can do. Nobody sits beside you while you build it into your business operations.\"\n        },\n        {\n            n: \"02\",\n            title: \"Workshops don't change operations.\",\n            body: \"Two-day seminars produce notes, not systems. Six months later, nothing runs differently in your company.\"\n        },\n        {\n            n: \"03\",\n            title: \"No peer network at your level.\",\n            body: \"The CEOs navigating this transformation alongside you are not in the same room. They should be.\"\n        },\n        {\n            n: \"04\",\n            title: \"The gap widens every quarter.\",\n            body: \"In SEA, CEOs who act on AI in 2026 will hold structural competitive advantages that are very difficult to close by 2028.\"\n        }\n    ]\n};\nconst PROGRAM = {\n    label: \"The program\",\n    title: \"What AI CEO Circle actually delivers\",\n    intro: \"Three core outcomes. Six months. You leave with AI systems running in your business — not just ideas in your head.\",\n    items: [\n        {\n            tag: \"Strategic foundation\",\n            title: \"AI strategy for CEOs\",\n            body: \"Build your company's AI roadmap from the top down. Not a generic framework — your specific business, decisions, and priorities.\"\n        },\n        {\n            tag: \"Signature deliverable\",\n            title: \"Your Digital CEO Twin\",\n            body: \"The signature deliverable. An AI system trained on your thinking, strategy, and judgment. Works while you lead.\"\n        },\n        {\n            tag: \"Built in your business\",\n            title: \"Agentic AI deployment\",\n            body: \"Build and deploy one working AI agent inside your business by the end of the program. Real implementation — no theory, no slides.\"\n        }\n    ]\n};\nconst TIMELINE = {\n    label: \"The format\",\n    title: \"A 6-month executive mentoring circle\",\n    intro: \"Built for leaders who execute. Approximately 4–6 hours per month. Sessions fit executive schedules.\",\n    steps: [\n        {\n            window: \"Month 1–2\",\n            title: \"Map your business and build your AI strategy\",\n            body: \"Map your decision flows and high-leverage processes. Build your company's AI roadmap. Begin your Digital CEO Twin architecture with Isaac and the MAXY AI team.\"\n        },\n        {\n            window: \"Month 3–4\",\n            title: \"Build your first AI agent\",\n            body: \"Hands-on implementation workshop: build and deploy one AI agent that removes a real operational bottleneck. No code required. MAXY AI's agentic AI team builds alongside you.\"\n        },\n        {\n            window: \"Month 5–6\",\n            title: \"Deploy your Digital CEO Twin and scale\",\n            body: \"Complete and activate your Digital CEO Twin. Expand AI systems across divisions. Build internal capability to keep scaling independently after the program ends.\"\n        },\n        {\n            window: \"Throughout\",\n            title: \"Monthly sessions + 1-on-1 with Isaac + peer CEO network\",\n            body: \"Small cohort, maximum 15. Jakarta and Singapore offline events (3 total). Private peer community. Direct access to Isaac Munandar and the MAXY AI leadership team.\"\n        }\n    ]\n};\nconst TESTIMONIALS = {\n    label: \"Social proof\",\n    title: \"What CEOs are saying\",\n    items: [\n        {\n            initials: \"RS\",\n            name: \"Reza S.\",\n            role: \"CEO, Manufacturing · Jakarta\",\n            quote: \"Before AI CEO Circle, I knew AI was important but had no idea where to start as a leader. After month 2, I had my first AI agent running our reporting process. 40 hours saved per month — from one build.\"\n        },\n        {\n            initials: \"AT\",\n            name: \"Andrea T.\",\n            role: \"Founder, FinTech · Singapore\",\n            quote: \"I've attended three AI programs before this. None of them changed how my company operates. AI CEO Circle is the first time I left a session with something actually built — not just notes.\"\n        },\n        {\n            initials: \"DW\",\n            name: \"Dian W.\",\n            role: \"President Director, Retail · Surabaya\",\n            quote: \"The peer network alone is worth it. Being in a room with 14 CEOs who are actually building AI — not just talking about it — changed my pace entirely. We hold each other accountable.\"\n        }\n    ]\n};\nconst QUALIFICATION = {\n    label: \"Qualification\",\n    title: \"Is this program for you?\",\n    forYou: [\n        \"You're a CEO, Founder, or C-Suite executive in Indonesia or Singapore\",\n        \"You know AI is transforming your industry and want to lead — not react\",\n        \"You're ready to build AI systems in your business, not just learn about them\",\n        \"You want a private peer network of senior leaders doing the same\",\n        \"You can commit 4–6 hours per month to hands-on implementation\"\n    ],\n    notForYou: [\n        \"You want a quick certification course with a completion badge\",\n        \"You prefer passive online learning with no peer accountability\",\n        \"You want to understand AI conceptually without building anything real\",\n        \"You're not yet in a decision-making role with authority to act\",\n        \"You expect transformation without commitment to the process\"\n    ]\n};\nconst MENTOR = {\n    label: \"Your mentor\",\n    title: \"Mentored by a practitioner who has done it\",\n    lead: {\n        initials: \"IM\",\n        name: \"Isaac Munandar\",\n        role: \"Co-Founder & CEO — MAXY AI\",\n        handle: \"@isaacmunandar.ai\",\n        bio: \"Isaac Munandar is the co-founder and CEO of MAXY AI — Southeast Asia's AI-driven edtech and enterprise AI transformation company. He has helped companies across Indonesia and Singapore deploy AI systems, agentic AI solutions, and digital transformation strategies at the executive level. Inside AI CEO Circle, he mentors alongside you — not from a stage, but in the room.\",\n        chips: [\n            \"Co-Founder & CEO, MAXY AI\",\n            \"Enterprise AI · Indonesia + Singapore\",\n            \"Agentic AI practitioner\",\n            \"Investor relations\",\n            \"Serial entrepreneur\"\n        ]\n    },\n    team: [\n        {\n            initials: \"AT\",\n            name: \"Andy Toro\",\n            role: \"Co-Founder & CTO — International tech architecture and AI systems\"\n        },\n        {\n            initials: \"IK\",\n            name: \"Ika\",\n            role: \"Operations Director — Program delivery and logistics\"\n        },\n        {\n            initials: \"SF\",\n            name: \"Stefen\",\n            role: \"Product Manager — Platform, tools, and program infrastructure\"\n        }\n    ]\n};\nconst AFTERMATH = {\n    label: \"After AI CEO Circle\",\n    title: \"AI CEO Circle is the beginning, not the end\",\n    intro: \"Graduates unlock access to MAXY AI's full enterprise transformation ecosystem.\",\n    steps: [\n        {\n            tag: \"Step 2\",\n            title: \"AI training for your team\",\n            body: \"MAXY AI Digital Training — function-specific AI upskilling for your entire organization (HR, sales, marketing, ops, finance).\"\n        },\n        {\n            tag: \"Step 3\",\n            title: \"Agentic AI solutions\",\n            body: \"MAXY AI builds and deploys agentic AI systems inside your operations — automating high-leverage workflows across divisions.\"\n        },\n        {\n            tag: \"Step 4\",\n            title: \"AI-native talent placement\",\n            body: \"Hire pre-certified AI talent from MAXY Academy's graduate pipeline — directly into your AI-transformed organization.\"\n        }\n    ]\n};\nconst FAQ = {\n    label: \"FAQ\",\n    title: \"Common questions\",\n    items: [\n        {\n            q: \"Do I need technical AI knowledge to join?\",\n            a: \"No. This program is designed for business leaders, not engineers. MAXY AI's technical team handles all implementation — your role is strategic direction and accountability to outcomes. If you can lead a company, you can do this.\"\n        },\n        {\n            q: \"How much time does this require?\",\n            a: \"Approximately 4–6 hours per month. One group mentoring session, one implementation workshop, and optional 1-on-1 time with Isaac. Structured around executive schedules.\"\n        },\n        {\n            q: \"What tangible outcomes do I leave with?\",\n            a: \"One working AI agent deployed inside your business. Your Digital CEO Twin built and activated. A personalized AI strategy roadmap for your company. Permanent access to the AI CEO Circle peer network across Indonesia and Singapore.\"\n        },\n        {\n            q: \"What language are sessions delivered in?\",\n            a: \"Bilingual — English and Bahasa Indonesia — to serve both Indonesia and Singapore executives comfortably. Materials are available in both languages.\"\n        },\n        {\n            q: \"What is the program investment?\",\n            a: \"Program pricing is shared after your application is reviewed and a discovery call is completed. AI CEO Circle uses an application and selection process — not everyone is accepted. The cohort is small, and peer quality is part of the value.\"\n        },\n        {\n            q: \"What happens after the 6 months?\",\n            a: \"Graduates unlock direct access to MAXY AI's full ecosystem: AI training for your entire team, agentic AI systems built inside your operations, and AI-native talent from MAXY Academy's graduate pipeline. AI CEO Circle is the entry point to a full company-level AI transformation journey.\"\n        },\n        {\n            q: \"Who runs the program?\",\n            a: \"Isaac Munandar leads all mentoring sessions personally. The MAXY AI team — Andy Toro (CTO), Stefen (PM), Ika (Ops) — supports the implementation, platform, and program delivery. This is not outsourced. The MAXY AI founding team is in the room with you.\"\n        }\n    ]\n};\nconst FINAL_CTA = {\n    eyebrow: \"15 seats · Cohort 01 · September 2026\",\n    titleA: \"15 seats. One cohort.\",\n    titleB: \"This is your move.\",\n    body: \"The CEOs who will lead the next 5 years are the ones who act on AI in the next 6 months — not the ones who plan to. AI CEO Circle is MAXY AI's most exclusive program. If you're ready to build, not just learn, apply now.\",\n    primary: \"Apply for the next cohort\",\n    secondary: \"Download program overview\"\n};\nconst FOOTER = {\n    contact: [\n        {\n            label: \"DM\",\n            value: \"@aiceocircle\"\n        },\n        {\n            label: \"Email\",\n            value: \"hello@aiceocircle.com\"\n        }\n    ],\n    columns: [\n        {\n            title: \"Program\",\n            links: [\n                \"Ecosystem\",\n                \"Format\",\n                \"Mentor\",\n                \"FAQ\",\n                \"Apply\"\n            ]\n        },\n        {\n            title: \"MAXY AI\",\n            links: [\n                \"MAXY Academy\",\n                \"Digital Training\",\n                \"Agentic AI\",\n                \"Talent\"\n            ]\n        },\n        {\n            title: \"Reach\",\n            links: [\n                \"Jakarta\",\n                \"Singapore\",\n                \"hello@aiceocircle.com\",\n                \"@aiceocircle\"\n            ]\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/components/landing/data.js\n");

